        >
          <Typography
            sx={{
              textShadow:
                activeTab === index
                  ? theme.palette.mode === "dark"
                    ? "0 0 5px rgba(255,255,255,0.7)"
                    : "0 0 5px rgba(0,0,0,0.35)"
                  : "0 0 2px rgba(0,0,0,0.15)",
              color:
                activeTab === index
                  ? theme.palette.mode === "dark"
                    ? "#fff"
                    : "#000"
                  : theme.palette.mode === "dark"
                  ? "#aaa"
                  : "#666",
            }}
          >
            {tab}
          </Typography>
        </motion.div>
      ))}
    </Box>
  );
};

export default ElevatedCardsTabs;

